use strict;
use warnings;

sub is_palindrome {
    my ($text) = @_;
    my $cleaned = lc($text);
    $cleaned =~ s/\s+//g;
    my $reversed = reverse $cleaned;
    return $cleaned eq $reversed;
}

sub is_number_palindrome {
    my ($number) = @_;
    my $text = "$number";
    my $reversed = reverse $text;
    return $text eq $reversed;
}

my @words = ("kayak", "araba", "anna", "elma", "a man a plan a canal panama");

print "Kelime testleri:\n";
foreach my $word (@words) {
    print "'$word' palindrome mu: " . (is_palindrome($word) ? "evet" : "hayir") . "\n";
}

print "\nSayi testleri:\n";
my @numbers = (12321, 12345, 1001, 5);
foreach my $num (@numbers) {
    print "$num palindrome mu: " . (is_number_palindrome($num) ? "evet" : "hayir") . "\n";
}
